import { zodResolver } from "@hookform/resolvers/zod";
import { motion, AnimatePresence } from "framer-motion";
import { CheckCircle2, Loader2, Send } from "lucide-react";
import { contactSchema, type ContactFormValues } from "@/lib/schemas/contact";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export default function ContactForm() {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors },
    reset,
  } = useForm<ContactFormValues>({
    resolver: zodResolver(contactSchema),
    mode: "onTouched",
  });

  const onSubmit = async (data: ContactFormValues) => {
    setIsSubmitting(true);

    // Simulate API delay
    await new Promise((resolve) => setTimeout(resolve, 1500));

    // Log exactly as requested
    console.log("=== Contact Form Submitted ===");
    console.log(JSON.stringify(data, null, 2));
    console.log("==============================");

    setIsSubmitting(false);
    setIsSuccess(true);
  };

  return (
    <div className="bg-white rounded-3xl p-8 md:p-12 shadow-xl border border-border relative overflow-hidden">
      {/* Decorative top border */}
      <div className="absolute top-0 left-0 w-full h-2 bg-primary" />

      <AnimatePresence mode="wait">
        {isSuccess ? (
          <motion.div
            key="success"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="text-center py-12"
          >
            <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <CheckCircle2 className="w-10 h-10 text-green-600" />
            </div>
            <h3 className="font-display font-bold text-3xl text-text mb-4">Message Sent!</h3>
            <p className="font-body text-text-muted text-lg mb-8 max-w-sm mx-auto">
              Thank you for reaching out to us. Our team will get back to you shortly.
            </p>
            <Button 
              onClick={() => {
                reset();
                setIsSuccess(false);
              }}
              variant="outline"
              className="rounded-full px-8 font-body"
            >
              Send Another Message
            </Button>
          </motion.div>
        ) : (
          <motion.form
            key="form"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onSubmit={handleSubmit(onSubmit)}
            className="space-y-6"
            noValidate
          >
            <div className="mb-8">
              <h3 className="font-display font-bold text-3xl text-text mb-2">Send us a Message</h3>
              <p className="font-body text-text-muted">Fill out the form below and we'll be in touch.</p>
            </div>

            <div className="space-y-2">
              <Label htmlFor="contact-name">Full Name</Label>
              <Input 
                id="contact-name" 
                placeholder="John Doe" 
                {...register("name")} 
                aria-invalid={errors.name ? "true" : "false"}
                aria-describedby={errors.name ? "name-error" : undefined}
                className={errors.name ? "border-red-500 focus-visible:ring-red-500" : ""}
              />
              <div aria-live="polite" id="name-error">
                {errors.name && <p className="text-sm text-red-500 font-body mt-1">{errors.name.message}</p>}
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="contact-email">Email Address</Label>
              <Input 
                id="contact-email" 
                type="email" 
                placeholder="john@example.com" 
                {...register("email")} 
                aria-invalid={errors.email ? "true" : "false"}
                aria-describedby={errors.email ? "email-error" : undefined}
                className={errors.email ? "border-red-500 focus-visible:ring-red-500" : ""}
              />
              <div aria-live="polite" id="email-error">
                {errors.email && <p className="text-sm text-red-500 font-body mt-1">{errors.email.message}</p>}
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="contact-subject">Subject</Label>
              <Input 
                id="contact-subject" 
                placeholder="How can we help you?" 
                {...register("subject")} 
                aria-invalid={errors.subject ? "true" : "false"}
                aria-describedby={errors.subject ? "subject-error" : undefined}
                className={errors.subject ? "border-red-500 focus-visible:ring-red-500" : ""}
              />
              <div aria-live="polite" id="subject-error">
                {errors.subject && <p className="text-sm text-red-500 font-body mt-1">{errors.subject.message}</p>}
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="contact-message">Message</Label>
              <textarea 
                id="contact-message" 
                rows={5}
                {...register("message")}
                aria-invalid={errors.message ? "true" : "false"}
                aria-describedby={errors.message ? "message-error" : undefined}
                className={`w-full flex rounded-md border bg-transparent px-3 py-2 text-sm shadow-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 disabled:cursor-not-allowed disabled:opacity-50 ${
                  errors.message ? "border-red-500 focus-visible:ring-red-500" : "border-input focus-visible:ring-ring"
                }`}
                placeholder="Tell us more about your inquiry..."
              />
              <div aria-live="polite" id="message-error">
                {errors.message && <p className="text-sm text-red-500 font-body mt-1">{errors.message.message}</p>}
              </div>
            </div>

            <Button 
              type="submit" 
              size="lg" 
              className="w-full bg-primary text-white hover:bg-primary-dark transition-colors font-body text-lg group"
              disabled={isSubmitting}
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                  Sending...
                </>
              ) : (
                <>
                  Send Message
                  <Send className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform" />
                </>
              )}
            </Button>
          </motion.form>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";

import { MapPin, ArrowRight } from "lucide-react";
import type { Event } from "@/lib/types";

interface EventTabsGridProps {
  events: Event[];
}

export default function EventTabsGrid({ events }: EventTabsGridProps) {
  const [activeTab, setActiveTab] = useState<"Upcoming" | "Past">("Upcoming");

  const currentDate = new Date();

  const upcomingEvents = events.filter(e => new Date(e.date) > currentDate);
  const pastEvents = events.filter(e => new Date(e.date) <= currentDate);

  const displayedEvents = activeTab === "Upcoming" ? upcomingEvents : pastEvents;

  return (
    <section className="py-12 md:py-24 bg-bg">
      <div className="max-w-7xl mx-auto px-6 sm:px-8 lg:px-12">

        {/* Tabs */}
        <div className="flex justify-center mb-16">
          <div className="bg-white border border-border p-1 rounded-full inline-flex shadow-sm">
            <button
              onClick={() => setActiveTab("Upcoming")}
              className={`px-8 py-3 rounded-full font-body text-sm font-bold transition-all ${
                activeTab === "Upcoming"
                  ? "bg-primary text-white shadow-md"
                  : "text-text-muted hover:text-primary"
              }`}
            >
              Upcoming Events
            </button>
            <button
              onClick={() => setActiveTab("Past")}
              className={`px-8 py-3 rounded-full font-body text-sm font-bold transition-all ${
                activeTab === "Past"
                  ? "bg-primary text-white shadow-md"
                  : "text-text-muted hover:text-primary"
              }`}
            >
              Past Events
            </button>
          </div>
        </div>

        {/* Grid */}
        <motion.div 
          layout 
          className="grid grid-cols-1 md:grid-cols-2 gap-8"
        >
          <AnimatePresence mode="popLayout">
            {displayedEvents.map((event) => {
              const capacityPercent = Math.min(100, Math.round((event.registered || 0) / (event.capacity || 1) * 100));
              const isPast = activeTab === "Past";

              return (
                <motion.div
                  key={event.id}
                  layout
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  transition={{ duration: 0.3 }}
                  className={`bg-white rounded-3xl overflow-hidden shadow-lg border border-border flex flex-col group ${isPast ? 'opacity-80 grayscale-[30%]' : 'hover:shadow-xl transition-shadow'}`}
                >
                  <div className="relative w-full h-64 overflow-hidden">
                    <Image
                      src={event.image}
                      alt={event.title}
                      fill
                      sizes="(max-width: 768px) 100vw, 50vw"
                      className={`object-cover ${!isPast && 'group-hover:scale-105 transition-transform duration-700'}`}
                    />
                    {/* Date Badge */}
                    <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-sm px-4 py-2 rounded-2xl text-center shadow-md">
                      <div className="font-accent font-bold text-primary text-sm uppercase">
                        {new Date(event.date).toLocaleDateString('en-US', { month: 'short' })}
                      </div>
                      <div className="font-display font-bold text-text text-2xl leading-none mt-1">
                        {new Date(event.date).getDate()}
                      </div>
                    </div>
                    {/* Category Tag */}
                    <div className="absolute top-4 right-4 bg-bg-dark/80 backdrop-blur-sm px-3 py-1 rounded-full">
                      <span className="font-accent text-xs font-bold uppercase tracking-wider text-white">
                        {event.category}
                      </span>
                    </div>
                  </div>

                  <div className="p-8 flex flex-col flex-grow">
                    <h3 className="font-display font-bold text-2xl text-text mb-3">
                      {event.title}
                    </h3>

                    <div className="flex flex-col gap-2 mb-6">
                      <div className="flex items-center text-text-muted font-body text-sm">
                        <MapPin className="w-4 h-4 mr-2 text-primary" />
                        {event.location}, {event.state}
                      </div>
                      <div className="flex items-center text-text-muted font-body text-sm">
                        <Calendar className="w-4 h-4 mr-2 text-primary" />
                        {new Date(event.date).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} at {event.time}
                      </div>
                    </div>

                    {!isPast && event.capacity && (
                      <div className="mb-8">
                        <div className="flex justify-between text-xs font-body text-text-muted mb-2">
                          <span className="font-medium">Registration Capacity</span>
                          <span>{event.registered} / {event.capacity} filled</span>
                        </div>
                        <div className="w-full bg-bg h-2 rounded-full overflow-hidden">
                          <div 
                            className={`h-full rounded-full ${capacityPercent >= 90 ? 'bg-red-500' : 'bg-primary'}`}
                            style={{ width: `${capacityPercent}%` }}
                          />
                        </div>
                      </div>
                    )}

                    <div className="mt-auto pt-4">
                      <Link 
                        href={`/events/${event.id}`}
                        className={`flex items-center justify-center w-full py-3 px-6 rounded-xl font-body font-bold transition-all group/btn ${
                          isPast 
                            ? "bg-bg text-text hover:bg-gray-200" 
                            : "bg-primary text-white hover:bg-primary-dark"
                        }`}
                      >
                        {isPast ? "View Recap" : "Register Now"}
                        <ArrowRight className="w-5 h-5 ml-2 group-hover/btn:translate-x-1 transition-transform" />
                      </Link>
                    </div>
                  </div>
                </motion.div>
              );
            })}
          </AnimatePresence>
        </motion.div>

        {displayedEvents.length === 0 && (
          <div className="text-center py-20">
            <p className="font-body text-text-muted text-lg">No events found in this category.</p>
          </div>
        )}

      </div>
    </section>
  );
}

"use client";

import { useState, useEffect } from "react";
import { ComposableMap, Geographies, Geography, ZoomableGroup } from "react-simple-maps";
import { motion, AnimatePresence } from "framer-motion";
import { Users, BookOpen, TrendingUp, CheckCircle2 } from "lucide-react";

// India TopoJSON from local assets
const GEO_URL = "/assets/india.topo.json";

interface StateData {
  id: string;
  name: string;
  programsRunning: number;
  beneficiaries: number;
  volunteers: number;
  successStories: number;
  activePrograms: string[];
  highlight: boolean;
}

interface IndiaMapProps {
  data: StateData[];
}

export default function IndiaMap({ data }: IndiaMapProps) {
  const [isMounted, setIsMounted] = useState(false);
  const [activeState, setActiveState] = useState<StateData | null>(null);

  // Prevent Hydration Errors & CLS
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setIsMounted(true);
  }, []);

  // Normalization helper to match map-data.json id/name with TopoJSON properties
  const getMappedData = (geo: any): StateData | undefined => {
    const geoName = geo.properties.name || geo.properties.ST_NM || geo.properties.st_nm || geo.id || "";
    // Match by exact name or normalized ID
    return data.find(
      (d) =>
        d.name.toLowerCase() === geoName.toLowerCase() ||
        d.id.toLowerCase() === geoName.toLowerCase().replace(/\s+/g, "-")
    );
  };

  const handleStateClick = (geo: any) => {
    const matchedData = getMappedData(geo);
    if (matchedData) {
      setActiveState(matchedData);
    } else {
      // Create a dummy state if no data exists, so the UI still responds
      const name = geo.properties.name || geo.properties.ST_NM || geo.properties.st_nm || "Unknown State";
      setActiveState({
        id: name.toLowerCase().replace(/\s+/g, "-"),
        name: name,
        programsRunning: 0,
        beneficiaries: 0,
        volunteers: 0,
        successStories: 0,
        activePrograms: ["Planning phase"],
        highlight: false,
      });
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent, geo: any) => {
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      handleStateClick(geo);
    }
  };

  if (!isMounted) {
    // Explicit aspect-ratio skeleton to prevent CLS
    return (
      <div className="w-full h-full min-h-[500px] aspect-[4/5] md:aspect-square lg:aspect-[4/3] bg-gray-50 rounded-3xl animate-pulse flex items-center justify-center border border-border">
        <span className="font-body text-text-muted">Loading Interactive Map...</span>
      </div>
    );
  }

  return (
    <div className="w-full flex flex-col lg:flex-row gap-8 lg:gap-12 items-start">

      {/* MAP CONTAINER */}
      <div className="w-full lg:w-3/5 bg-white rounded-3xl shadow-xl border border-border p-4 relative overflow-hidden min-h-[400px] md:min-h-[500px] lg:h-[650px] flex items-center justify-center">
        <ComposableMap
          projection="geoMercator"
          projectionConfig={{
            scale: 1000,
            center: [80, 22] // Approximate center of India
          }}
          className="w-full h-full object-contain outline-none"
        >
          <ZoomableGroup center={[80, 22]} zoom={1} minZoom={1} maxZoom={4}>
            <Geographies geography={GEO_URL}>
              {({ geographies }) =>
                geographies.map((geo) => {
                  const stateData = getMappedData(geo);
                  const isHighlighted = stateData?.highlight;
                  const isActive = activeState?.name === (geo.properties.name || geo.properties.ST_NM || geo.properties.st_nm);

                  return (
                    <Geography
                      key={geo.rsmKey}
                      geography={geo}
                      role="button"
                      tabIndex={0}
                      aria-label={geo.properties.name || geo.properties.ST_NM || geo.properties.st_nm}
                      onClick={() => handleStateClick(geo)}
                      onKeyDown={(e) => handleKeyDown(e, geo)}
                      className="outline-none"
                      style={{
                        default: {
                          fill: isActive ? "#F26522" : isHighlighted ? "#A7F3D0" : "#E2E8F0",
                          stroke: "#94A3B8",
                          strokeWidth: 0.75,
                          outline: "none",
                          transition: "all 0.3s ease",
                        },
                        hover: {
                          fill: isActive ? "#F26522" : "#1A6B3C",
                          stroke: "#94A3B8",
                          strokeWidth: 1,
                          outline: "none",
                          cursor: "pointer",
                          transition: "all 0.3s ease",
                        },
                        pressed: {
                          fill: "#F26522",
                          stroke: "#94A3B8",
                          strokeWidth: 1,
                          outline: "none",
                        },
                      }}
                    />
                  );
                })
              }
            </Geographies>
          </ZoomableGroup>
        </ComposableMap>

        {/* Legend */}
        <div className="absolute bottom-6 right-6 bg-white/95 backdrop-blur-sm p-4 rounded-2xl border border-border shadow-md flex flex-col gap-3 pointer-events-none z-10">
          <div className="flex items-center gap-3">
            <div className="w-4 h-4 rounded-full bg-[#E2E8F0] border border-gray-400" />
            <span className="font-body text-sm font-medium text-text-muted">Standard</span>
          </div>
          <div className="flex items-center gap-3">
            <div className="w-4 h-4 rounded-full bg-[#A7F3D0] border border-gray-400" />
            <span className="font-body text-sm font-medium text-text-muted">High Activity</span>
          </div>
          <div className="flex items-center gap-3">
            <div className="w-4 h-4 rounded-full bg-[#F26522]" />
            <span className="font-body text-sm font-medium text-text-muted">Selected</span>
          </div>
        </div>
      </div>

      {/* STATS PANEL */}
      <div className="w-full lg:w-2/5 lg:h-[650px]">
        <AnimatePresence mode="wait">
          {activeState ? (
            <motion.div
              key={activeState.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.3 }}
              className="bg-white rounded-3xl shadow-xl border border-border p-8 h-full flex flex-col relative overflow-hidden"
            >
              {/* Decorative Banner */}
              <div className="absolute top-0 left-0 right-0 h-3 bg-primary" />

              <h3 className="font-display font-bold text-3xl md:text-4xl text-text mb-2 mt-2">
                {activeState.name}
              </h3>
              <p className="font-body text-primary font-semibold mb-8 uppercase tracking-wider text-sm">
                Regional Impact Report
              </p>

              <div className="grid grid-cols-2 gap-6 mb-8">
                <div className="bg-bg rounded-2xl p-4 border border-border">
                  <BookOpen className="w-6 h-6 text-primary mb-2" />
                  <p className="font-display font-bold text-2xl text-text">{activeState.programsRunning}</p>
                  <p className="font-body text-text-muted text-sm">Active Programs</p>
                </div>
                <div className="bg-bg rounded-2xl p-4 border border-border">
                  <Users className="w-6 h-6 text-primary mb-2" />
                  <p className="font-display font-bold text-2xl text-text">{activeState.beneficiaries.toLocaleString()}+</p>
                  <p className="font-body text-text-muted text-sm">Beneficiaries</p>
                </div>
                <div className="bg-bg rounded-2xl p-4 border border-border">
                  <CheckCircle2 className="w-6 h-6 text-primary mb-2" />
                  <p className="font-display font-bold text-2xl text-text">{activeState.volunteers.toLocaleString()}</p>
                  <p className="font-body text-text-muted text-sm">Volunteers</p>
                </div>
                <div className="bg-bg rounded-2xl p-4 border border-border">
                  <TrendingUp className="w-6 h-6 text-primary mb-2" />
                  <p className="font-display font-bold text-2xl text-text">{activeState.successStories}</p>
                  <p className="font-body text-text-muted text-sm">Success Stories</p>
                </div>
              </div>

              <div className="mt-auto">
                <h4 className="font-display font-bold text-lg text-text mb-4">Current Initiatives</h4>
                <ul className="space-y-3">
                  {activeState.activePrograms.map((program, idx) => (
                    <li key={idx} className="flex items-start">
                      <span className="w-2 h-2 rounded-full bg-primary mt-2 mr-3 shrink-0" />
                      <span className="font-body text-text-muted leading-relaxed">{program}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </motion.div>
          ) : (
            <motion.div
              key="empty"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="bg-bg rounded-3xl border-2 border-dashed border-border p-12 h-full flex flex-col items-center justify-center text-center"
            >
              <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-sm">
                <Users className="w-10 h-10 text-primary/40" />
              </div>
              <h3 className="font-display font-bold text-2xl text-text mb-3">Explore Our Reach</h3>
              <p className="font-body text-text-muted text-lg max-w-sm">
                Click or tap on any state on the map to view detailed grassroots impact metrics and active programs for that region.
              </p>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { fadeIn } from "@/lib/motion";
import { CheckCircle2 } from "lucide-react";

const formSchema = z.object({
  email: z.string().email("Please enter a valid email address."),
});

type FormValues = z.infer<typeof formSchema>;

export function NewsletterBanner() {
  const [isSuccess, setIsSuccess] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm<FormValues>({
    resolver: zodResolver(formSchema),
  });

  const onSubmit = async (data: FormValues) => {
    // Simulate network delay for realistic feel
    await new Promise((resolve) => setTimeout(resolve, 800));
    setIsSuccess(true);
  };

  return (
    <section className="py-12 md:py-24 bg-primary relative overflow-hidden">
      {/* Decorative radial gradient to add depth */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(255,255,255,0.15)_0%,transparent_70%)] pointer-events-none"></div>

      <div className="max-w-4xl mx-auto px-6 sm:px-8 lg:px-12 text-center relative z-10">
        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: "-100px" }}
          variants={fadeIn}
          className="flex flex-col items-center"
        >
          <span className="inline-block mb-4 text-white font-accent font-semibold text-sm tracking-widest uppercase shadow-sm">
            STAY CONNECTED
          </span>

          <h2 className="font-display font-bold text-3xl md:text-5xl text-white mb-6">
            Join the Disha Movement
          </h2>

          <p className="font-body text-white/90 text-lg md:text-xl max-w-2xl mx-auto mb-10 leading-relaxed">
            Get updates on programs, events, and impact stories delivered to your inbox.
          </p>

          {isSuccess ? (
            <motion.div 
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              className="bg-white/10 backdrop-blur-md border border-white/20 rounded-2xl p-6 flex items-center gap-4 text-white shadow-lg"
            >
              <CheckCircle2 className="w-10 h-10 text-white shrink-0" />
              <div className="text-left">
                <p className="font-display font-bold text-2xl mb-1">You're in!</p>
                <p className="font-body text-white/90">Welcome to the Disha family.</p>
              </div>
            </motion.div>
          ) : (
            <div className="w-full max-w-lg mx-auto">
              <form 
                onSubmit={handleSubmit(onSubmit)} 
                className="flex flex-col md:flex-row gap-3 md:gap-2 w-full items-start"
              >
                <div className="relative w-full">
                  <input
                    {...register("email")}
                    type="email"
                    placeholder="Enter your email"
                    className="w-full bg-white text-text rounded-full px-6 py-4 outline-none focus:ring-4 focus:ring-white/30 transition-all placeholder:text-gray-400 font-body shadow-md"
                    disabled={isSubmitting}
                  />
                  {errors.email && (
                    <span className="absolute left-4 top-[105%] text-white text-sm font-medium drop-shadow-sm">
                      {errors.email.message}
                    </span>
                  )}
                </div>

                <button
                  type="submit"
                  disabled={isSubmitting}
                  className="w-full md:w-auto bg-bg-dark text-white rounded-full px-8 py-4 font-semibold hover:bg-secondary transition-colors font-body whitespace-nowrap shadow-md disabled:opacity-70 disabled:cursor-not-allowed"
                >
                  {isSubmitting ? "Subscribing..." : "Subscribe"}
                </button>
              </form>

              <p className="mt-8 text-white/70 font-body text-sm font-medium">
                No spam. Unsubscribe anytime.
              </p>
            </div>
          )}
        </motion.div>
      </div>
    </section>
  );
}

