data.forEach(file => {
  if (file.messages.length === 0) return;
  if (file.filePath.includes('scratch')) return; // Ignore scratch files

  let content = fs.readFileSync(file.filePath, 'utf8');
  let lines = content.split('\n');

  file.messages.sort((a, b) => b.line - a.line).forEach(msg => {
    const lineIndex = msg.line - 1;
    let line = lines[lineIndex];

    if (msg.ruleId === 'react/no-unescaped-entities') {
      line = line.replace(/'/g, "&apos;").replace(/"/g, "&quot;");
      lines[lineIndex] = line;
    } 
    else if (msg.ruleId === '@typescript-eslint/no-explicit-any') {
      line = line.replace(/any/g, "unknown"); // mostly safe fallback
      lines[lineIndex] = line;
    }
    else if (msg.ruleId === 'react/jsx-no-undef') {
      // Missing imports
      if (msg.message.includes('Users')) {
        // Add to lucide-react import
        for(let i=0; i<20; i++) {
           if(lines[i] && lines[i].includes('lucide-react')) {
               if(!lines[i].includes('Users')) {
                   lines[i] = lines[i].replace('{', '{ Users,');
               }
               break;
           }
        }
      }
      if (msg.message.includes('Calendar')) {
        for(let i=0; i<20; i++) {
           if(lines[i] && lines[i].includes('lucide-react')) {
               if(!lines[i].includes('Calendar')) {
                   lines[i] = lines[i].replace('{', '{ Calendar,');
               }
               break;
           }
        }
      }
    }
    else if (msg.ruleId === '@typescript-eslint/no-unused-vars') {
      const v = msg.message.match(/'(.*?)'/)[1];
      if (['slideUp', 'staggerChildren', 'SuccessStory'].includes(v)) {
        line = line.replace(new RegExp(`\\b${v},?\\s*`), '');
      } else if (v === 'data' && file.filePath.includes('NewsletterBanner')) {
        line = line.replace(/const data =.*?\];/g, '');
      } else if (['control', 'watch'].includes(v)) {
        line = line.replace(new RegExp(`\\b${v},?\\s*`), '');
      } else if (['personalStepSchema', 'interestStepSchema', 'availabilityStepSchema'].includes(v)) {
        line = ""; // remove the line
      }
    }
  });

  // Re-join and fix empty import brackets `import { } from`
  content = lines.join('\n');
  content = content.replace(/import\s*\{\s*\}\s*from\s*["'].*["'];?/g, '');

  fs.writeFileSync(file.filePath, content);
});

console.log("Secondary fixes applied successfully.");
